import pytest

from your_module import partial


def test_partial_happy_path_positional_only():
    def add(a, b, c):
        return a + b + c

    p = partial(add, 1, 2)
    assert p(3) == 6


def test_partial_happy_path_keyword_only():
    def greet(first, last, title):
        return f"{title} {first} {last}"

    p = partial(greet, title="Dr.")
    assert p("Ada", "Lovelace") == "Dr. Ada Lovelace"


def test_partial_combination_positional_and_keyword():
    def f(a, b, c, d=0):
        return a + b + c + d

    p = partial(f, 10, d=5)
    assert p(1, 2) == 18   # 10 + 1 + 2 + 5


def test_partial_keyword_override_by_call_arguments():
    def f(a, b=0):
        return a + b

    p = partial(f, b=10)
    assert p(5, b=3) == 8   # call kwargs override partial kwargs


def test_partial_no_extra_args():
    def f():
        return "ok"

    p = partial(f)
    assert p() == "ok"


def test_partial_empty_partial_kwargs_then_call_kwargs():
    def f(a=0, b=0):
        return a * b

    p = partial(f)
    assert p(a=3, b=4) == 12


def test_partial_error_missing_positional_arguments():
    def f(a, b):
        return a + b

    p = partial(f, 1)
    with pytest.raises(TypeError):
        # missing required 'b'
        p()


def test_partial_error_unexpected_keyword():
    def f(a):
        return a

    p = partial(f)
    with pytest.raises(TypeError):
        p(a=1, b=2)


def test_partial_with_none_arguments():
    def f(a, b):
        return (a, b)

    p = partial(f, None)
    assert p(5) == (None, 5)


def test_partial_order_of_kwargs_merge():
    def f(**kwargs):
        return kwargs

    p = partial(f, x=1, y=2)
    assert p(y=3, z=4) == {"x": 1, "y": 3, "z": 4}
